def fetch_avatar(username):
    url='https://www.tiktok.com/@'+urllib.parse.quote(username)
    hd={'User-Agent':'Mozilla/5.0 (iPhone; CPU iPhone OS 17_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/17.0 Mobile/15E148 Safari/604.1','Accept':'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8','Accept-Language':'en-US,en;q=0.9'}
    try:
        req=urllib.request.Request(url,headers=hd)
        with urllib.request.urlopen(req,timeout=8) as resp:
            html=resp.read().decode('utf-8',errors='ignore')
        pats=[r'"avatarLarger"\s*:\s*"([^"]+)"',r'"avatarMedium"\s*:\s*"([^"]+)"',r'"avatarThumb"\s*:\s*"([^"]+)"',r'og:image[^>]*content\s*=\s*"([^"]+)"']
        for pat in pats:
            m=re.search(pat,html)
            if m:
                au=m.group(1).replace('\\u002F','/')
                if au.startswith('http'):
                    try:
                        ir=urllib.request.Request(au,headers={'User-Agent':hd['User-Agent'],'Referer':'https://www.tiktok.com/'})
                        with urllib.request.urlopen(ir,timeout=8) as ir2:
                            ct=ir2.headers.get('Content-Type','image/jpeg')
                            img=ir2.read()
                            return 'data:'+ct+';base64,'+base64.b64encode(img).decode('ascii')
                    except:return au
    except:pass
    return None

class H(http.server.BaseHTTPRequestHandler):
    def do_GET(self):
        if self.path.startswith('/avatar'):
            self.send_response(200)
            self.send_header('Content-type','application/json')
            self.send_header('Access-Control-Allow-Origin','*')
            self.end_headers()
            parts=urllib.parse.urlparse(self.path)
            qs=urllib.parse.parse_qs(parts.query)
            u=qs.get('u',[''])[0]
            r={'url':None}
            if u:
                a=fetch_avatar(u)
                if a:r['url']=a
            self.wfile.write(json.dumps(r).encode('utf-8'))
        else:
            self.send_response(200)
            self.send_header('Content-type','text/html; charset=utf-8')
            self.end_headers()
            self.wfile.write(HTML.encode('utf-8'))
    def log_message(self,f,*a):pass

def get_ip():
    s=socket.socket(socket.AF_INET,socket.SOCK_DGRAM)
    try:s.connect(('10.255.255.255',1));return s.getsockname()[0]
    except:return '127.0.0.1'
    finally:s.close()

class ThreadedTCP(socketserver.ThreadingMixIn,socketserver.TCPServer):
    allow_reuse_address=True

